import{Errors,Functions,Log,ValueConverter}from"Beckhoff.TwinCAT.HMI.Framework/index.esm.js";export function BigIntToNumber(value){const res=ValueConverter.toNumberEx(value);if(res.error!==Errors.NONE)throw new Error("Converting bigint to number failed with: "+Log.buildMessage(res.details)+".");if(null===res.value)throw new Error("Converting bigint to number failed.");return res.value}Functions.registerFunctionEx("BigIntToNumber","TcHmi.Functions.Beckhoff",BigIntToNumber,{injectInGlobalObject:!0});